import { Buffer } from 'buffer';
import { Algorithm } from '@phantom/openapi-wallet-service';
export { Algorithm } from '@phantom/openapi-wallet-service';
export { Transaction, VersionedTransaction } from '@solana/web3.js';

interface Stamper {
    stamp(params: {
        data: Buffer;
        type?: "PKI";
        idToken?: never;
        salt?: never;
    }): Promise<string>;
    stamp(params: {
        data: Buffer;
        type: "OIDC";
        idToken: string;
        salt: string;
    }): Promise<string>;
    algorithm: Algorithm;
    type: "PKI" | "OIDC";
    idToken?: string;
    salt?: string;
}
interface StamperKeyInfo {
    keyId: string;
    publicKey: string;
    createdAt?: number;
    authenticatorId?: string;
}
interface StamperWithKeyManagement extends Stamper {
    init(): Promise<StamperKeyInfo>;
    getKeyInfo(): StamperKeyInfo | null;
    resetKeyPair(): Promise<StamperKeyInfo>;
    clear(): Promise<void>;
    rotateKeyPair(): Promise<StamperKeyInfo>;
    commitRotation(authenticatorId: string): Promise<void>;
    rollbackRotation(): Promise<void>;
}

export { Stamper, StamperKeyInfo, StamperWithKeyManagement };
